  +'<td style="width:25%;padding-right:6px"><table width="100%" bgcolor="#f7f5ff" style="border-radius:8px"><tr><td style="padding:12px;text-align:center"><p style="margin:0 0 3px;font-size:10px;font-weight:600;text-transform:uppercase;color:#9ca3af">Failed</p><p style="margin:0;font-size:22px;font-weight:800;color:'+(summary.failed>0?'#dc2626':'#9ca3af')+'">'+summary.failed+'</p></td></tr></table></td>'
  +'<td style="width:25%"><table width="100%" bgcolor="#f7f5ff" style="border-radius:8px"><tr><td style="padding:12px;text-align:center"><p style="margin:0 0 3px;font-size:10px;font-weight:600;text-transform:uppercase;color:#9ca3af">Total</p><p style="margin:0;font-size:22px;font-weight:800;color:#6C63FF">'+summary.total+'</p></td></tr></table></td>'
  +'</tr></table>'
  +'<table width="100%"><tr>'
  +'<th style="padding:6px 4px;font-size:10px;font-weight:600;color:#9ca3af;text-align:left;text-transform:uppercase">ID</th>'
  +'<th style="padding:6px 8px;font-size:10px;font-weight:600;color:#9ca3af;text-align:left;text-transform:uppercase">Scenario</th>'
  +'<th style="padding:6px 8px;font-size:10px;font-weight:600;color:#9ca3af;text-align:center;text-transform:uppercase">Result</th>'
  +'<th style="padding:6px 8px;font-size:10px;font-weight:600;color:#9ca3af;text-align:left;text-transform:uppercase">Score</th>'
  +'<th style="padding:6px 8px;font-size:10px;font-weight:600;color:#9ca3af;text-align:left;text-transform:uppercase">Service</th>'
  +'<th style="padding:6px 8px;font-size:10px;font-weight:600;color:#9ca3af;text-align:left;text-transform:uppercase">Notes</th>'
  +'</tr>'+rows+'</table>'
  +'</td></tr></table></td></tr></table></body></html>';
return [{ json: { html, subject: subj } }];

